// 기간 계산: 주간(월요일) / 월간(1일) / 수동(body.type)
let body = {};
try { body = $('수동 웹훅').first().json.body || {}; } catch(e) {}
const chatId = String(body.chatId || body.chat_id || '7713811206');

const now = new Date();
const kstNow = new Date(now.getTime() + 9 * 3600000);
const dayOfWeek = kstNow.getDay();
const dayOfMonth = kstNow.getDate();

const fmt = (d) => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  return y + '-' + m + '-' + dd;
};

let type, fromDate, toDate, label, prevFrom, prevTo, prevLabel;
const manualType = body.type || null;

if (manualType === 'monthly' || (!manualType && dayOfMonth === 1)) {
  type = 'monthly';
  const lastDay = new Date(kstNow);
  lastDay.setDate(0);
  const firstDay = new Date(lastDay.getFullYear(), lastDay.getMonth(), 1);
  fromDate = fmt(firstDay);
  toDate = fmt(lastDay);
  const mon = lastDay.getMonth() + 1;
  label = lastDay.getFullYear() + '\ub144 ' + mon + '\uc6d4 \uc6d4\uac04 \ub9ac\ud3ec\ud2b8';
  // \uc804\ub144 \ub3d9\uc6d4
  const pyLastDay = new Date(lastDay.getFullYear() - 1, lastDay.getMonth() + 1, 0);
  const pyFirstDay = new Date(lastDay.getFullYear() - 1, lastDay.getMonth(), 1);
  prevFrom = fmt(pyFirstDay);
  prevTo = fmt(pyLastDay);
  prevLabel = (lastDay.getFullYear() - 1) + '\ub144 ' + mon + '\uc6d4';
} else {
  type = 'weekly';
  const endOfWeek = new Date(kstNow);
  endOfWeek.setDate(kstNow.getDate() - (dayOfWeek === 0 ? 7 : dayOfWeek));
  const startOfWeek = new Date(endOfWeek);
  startOfWeek.setDate(endOfWeek.getDate() - 6);
  fromDate = fmt(startOfWeek);
  toDate = fmt(endOfWeek);
  const m1 = startOfWeek.getMonth() + 1;
  const d1 = startOfWeek.getDate();
  const m2 = endOfWeek.getMonth() + 1;
  const d2 = endOfWeek.getDate();
  label = m1 + '/' + d1 + '~' + m2 + '/' + d2 + ' \uc8fc\uac04 \ub9ac\ud3ec\ud2b8';
  // \uc804\uc8fc
  const prevEnd = new Date(startOfWeek);
  prevEnd.setDate(startOfWeek.getDate() - 1);
  const prevStart = new Date(prevEnd);
  prevStart.setDate(prevEnd.getDate() - 6);
  prevFrom = fmt(prevStart);
  prevTo = fmt(prevEnd);
  prevLabel = (prevStart.getMonth()+1) + '/' + prevStart.getDate() + '~' + (prevEnd.getMonth()+1) + '/' + prevEnd.getDate();
}

const fromYear = fromDate.slice(0, 4);
const prevYear = String(parseInt(fromYear) - 1);

return [{ json: {
  chatId, type, fromDate, toDate, label,
  prevFrom, prevTo, prevLabel,
  fromYear, prevYear,
} }];

// 주간/월간 리포트 생성
const info = $('기간 계산').first().json;
const cyResp = $('올해 NocoDB').first().json || {};
const pyResp = $('전년 NocoDB').first().json || {};
const cyList = cyResp.list || [];
const pyList = pyResp.list || [];

// 중복 제거
const dedupe = (list) => {
  const map = {};
  for (const r of list) {
    const d = r.report_date;
    if (!d) continue;
    if (!map[d] || r.Id > map[d].Id) map[d] = r;
  }
  return map;
};
const cyMap = dedupe(cyList);
const pyMap = dedupe(pyList);

// 기간 필터
const inRange = (d, from, to) => d >= from && d <= to;
const channels = ['makeshop', 'naver', 'st11', 'crm', 'coupang', 'rocket', 'legacy_others'];
const chNames = ['\uba54\uc774\ud06c\uc0f5', '\ub124\uc774\ubc84', '11\ubc88\uac00', '\uc9c1\uc811\uac70\ub798', '\ucfe0\ud321\uc719', '\ub85c\ucf13\ubc30\uc1a1', '\uae30\ud0c0'];
const chIcons = ['\ud83c\udfea', '\ud83d\udfe2', '\ud83d\udd34', '\ud83d\udcde', '\ud83d\udce6', '\ud83d\ude80', '\u26aa'];

// 현재 기간 집계
let totalRev = 0, totalOrd = 0;
const chRev = {};
channels.forEach(c => chRev[c] = 0);
const dailyData = [];

for (const d in cyMap) {
  if (!inRange(d, info.fromDate, info.toDate)) continue;
  const r = cyMap[d];
  const rev = parseInt(r.total_revenue || 0);
  totalRev += rev;
  totalOrd += parseInt(r.total_orders || 0);
  channels.forEach(c => chRev[c] += parseInt(r[c + '_revenue'] || 0));
  dailyData.push({ date: d, rev });
}
dailyData.sort((a, b) => a.date.localeCompare(b.date));

// 비교 기간 집계
let prevTotalRev = 0;
const prevChRev = {};
channels.forEach(c => prevChRev[c] = 0);

if (info.type === 'monthly') {
  // 전년 동월
  for (const d in pyMap) {
    if (!inRange(d, info.prevFrom, info.prevTo)) continue;
    const r = pyMap[d];
    prevTotalRev += parseInt(r.total_revenue || 0);
    channels.forEach(c => prevChRev[c] += parseInt(r[c + '_revenue'] || 0));
  }
} else {
  // 전주 (같은 해)
  for (const d in cyMap) {
    if (!inRange(d, info.prevFrom, info.prevTo)) continue;
    prevTotalRev += parseInt(cyMap[d].total_revenue || 0);
    channels.forEach(c => prevChRev[c] += parseInt(cyMap[d][c + '_revenue'] || 0));
  }
}

// 포맷 유틸
const fmt = (n) => Math.round(n).toLocaleString('ko-KR');
const pct = (part, whole) => whole > 0 ? Math.round(part / whole * 100) : 0;
const chg = (cur, prev) => {
  if (!prev || prev === 0) return '-';
  const diff = (cur - prev) / prev * 100;
  return (diff >= 0 ? '+' : '') + diff.toFixed(1) + '%';
};
const dowNames = ['\uc77c','\uc6d4','\ud654','\uc218','\ubaa9','\uae08','\ud1a0'];

let msg = '';

if (info.type === 'monthly') {
  msg += `<b>\ud83d\udcca ${info.label}</b>\n`;
  msg += '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n';
  msg += `\ud83d\udcb0 <b>\uc6d4 \ucd1d \ub9e4\ucd9c: ${fmt(totalRev)}\uc6d0</b>`;
  if (totalOrd > 0) msg += ` (${totalOrd}\uac74)`;
  msg += '\n';
  msg += `   \uc804\ub144 \ub3d9\uc6d4: ${fmt(prevTotalRev)}\uc6d0 (YoY ${chg(totalRev, prevTotalRev)})\n`;
  const days = dailyData.length;
  if (days > 0) msg += `   \uc77c\ud3c9\uade0: ${fmt(totalRev / days)}\uc6d0 (${days}\uc77c)\n`;
  msg += '\n<b>\ucc44\ub110\ubcc4:</b>\n';
  channels.forEach((c, i) => {
    if (chRev[c] > 0 || c === 'makeshop') {
      msg += `${chIcons[i]} ${chNames[i]}  ${fmt(chRev[c])}\uc6d0 (${pct(chRev[c], totalRev)}%)`;
      if (prevChRev[c] > 0) msg += ` [YoY ${chg(chRev[c], prevChRev[c])}]`;
      msg += '\n';
    }
  });
  // 주별 추이
  if (dailyData.length > 7) {
    msg += '\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n';
    msg += '<b>\uc8fc\ubcc4 \ucd94\uc774:</b>\n';
    let week = 1, weekRev = 0, weekStart = 1;
    for (let i = 0; i < dailyData.length; i++) {
      weekRev += dailyData[i].rev;
      const day = parseInt(dailyData[i].date.slice(8));
      if ((i + 1) % 7 === 0 || i === dailyData.length - 1) {
        msg += `W${week}(${weekStart}~${day}\uc77c) ${fmt(weekRev)}\uc6d0\n`;
        week++;
        weekRev = 0;
        weekStart = day + 1;
      }
    }
  }
} else {
  msg += `<b>\ud83d\udcca ${info.label}</b>\n`;
  msg += '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n';
  msg += `\ud83d\udcb0 <b>\uc8fc\uac04 \ucd1d \ub9e4\ucd9c: ${fmt(totalRev)}\uc6d0</b>`;
  if (totalOrd > 0) msg += ` (${totalOrd}\uac74)`;
  msg += '\n';
  msg += `   \uc804\uc8fc(${info.prevLabel}): ${fmt(prevTotalRev)}\uc6d0 (${chg(totalRev, prevTotalRev)})\n`;
  const days = dailyData.length;
  if (days > 0) msg += `   \uc77c\ud3c9\uade0: ${fmt(totalRev / days)}\uc6d0\n`;
  msg += '\n<b>\ucc44\ub110\ubcc4:</b>\n';
  channels.forEach((c, i) => {
    if (chRev[c] > 0 || c === 'makeshop') {
      msg += `${chIcons[i]} ${chNames[i]}  ${fmt(chRev[c])}\uc6d0 (${pct(chRev[c], totalRev)}%)`;
      if (prevChRev[c] > 0) msg += ` [${chg(chRev[c], prevChRev[c])}]`;
      msg += '\n';
    }
  });
  // 일별 차트
  msg += '\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n';
  msg += '<b>\uc77c\ubcc4:</b>\n';
  const maxRev = Math.max(...dailyData.map(d => d.rev), 1);
  for (const { date, rev } of dailyData) {
    const day = parseInt(date.slice(8));
    const d = new Date(date + 'T00:00:00Z');
    const dow = dowNames[d.getDay()];
    const barLen = Math.round(rev / maxRev * 8);
    const bar = '\u2588'.repeat(barLen) + '\u2581'.repeat(8 - barLen);
    msg += `${String(day).padStart(2)}(${dow}) ${bar} ${fmt(rev)}\n`;
  }
}

return [{ json: { chatId: info.chatId, message: msg, type: info.type } }];
